export const CART_LIMITS = {
  MAX_ITEMS: 10,
  MAX_WEIGHT_KG: 15
};

export const validateCartAddition = (cart, nuevoProducto, modoEntrega) => {
  // 1. Validar Local Único
  if (cart.length > 0 && cart[0].localId !== nuevoProducto.localId) {
    return { valid: false, msg: "Solo puedes pedir productos de un mismo local. Vacía el carrito para cambiar de comercio." };
  }

  // 2. Si es Retiro, no hay límites
  if (modoEntrega === 'retiro') return { valid: true };

  // 3. Validar Cantidad
  if (cart.length >= CART_LIMITS.MAX_ITEMS) {
    return { valid: false, msg: `Límite de delivery: máximo ${CART_LIMITS.MAX_ITEMS} productos.` };
  }

  // 4. Validar Peso
  const pesoActual = cart.reduce((acc, p) => acc + (Number(p.peso) || 0), 0);
  const pesoNuevo = Number(nuevoProducto.peso) || 0;
  
  if (pesoActual + pesoNuevo > CART_LIMITS.MAX_WEIGHT_KG) {
    return { valid: false, msg: `El pedido excedería los ${CART_LIMITS.MAX_WEIGHT_KG}kg (mochila del repartidor). Elige 'Retiro en Local' para llevar más.` };
  }

  return { valid: true };
};
